solutions.javascript:
// Solution
function generateCssGrid(gridItemSizes) {
  let maxItemSize = Math.max(...gridItemSizes);
  let totalItemSize = gridItemSizes.reduce((a, b) => a + parseInt(b), 0);
  // Correct spacing calculation
  let spacing = Math.floor(maxItemSize * gridItemSizes.length / totalItemSize);
  let cssLayout = `.grid-item { grid-column-gap: ${spacing}px; grid-row-gap: ${spacing}px; }
.grid { display: grid; grid-template-columns: repeat(3, 1fr); grid-template-rows: repeat(4, 1fr); grid-gap: ${spacing}px; }`;
  return cssLayout;
}
